/**
 * Bundles the individual .d.ts files generated by ts-loader into a single
 * self-contained declaration file for npm consumers.
 *
 * Reads .temp/tsc/spector.d.ts (the entry point) and recursively inlines
 * all local imports, stripping SCSS side-effect imports. The result is
 * written to dist/spector.d.ts.
 *
 * No external dependencies — uses only Node built-ins.
 */
const fs = require("fs");
const path = require("path");

const TEMP_DIR = path.resolve(__dirname, "../.temp/tsc");
const OUT_FILE = path.resolve(__dirname, "../dist/spector.d.ts");

const visited = new Set();
const chunks = [];
/** @type {Map<string, string>} alias -> original name */
const aliases = new Map();

/**
 * Recursively collect declarations from a .d.ts file, inlining local imports.
 */
function collect(filePath) {
    const resolved = path.resolve(filePath);
    if (visited.has(resolved)) return;
    visited.add(resolved);

    const content = fs.readFileSync(resolved, "utf-8");
    const lines = content.split("\n");
    const kept = [];

    for (const line of lines) {
        // Match local imports/re-exports: import/export ... from "./local/path"
        const m = line.match(/^(?:import|export)\s.*from\s+["'](\.[^"']+)["'];?\s*$/);
        if (m) {
            const target = m[1];
            if (/\.s?css$/.test(target)) continue;

            // Inline the dependency first
            const targetPath = resolveDecl(path.dirname(resolved), target);
            if (targetPath) collect(targetPath);

            // Record aliases from `import { X as Y }` for later text replacement
            if (line.trimStart().startsWith("import")) {
                const braceMatch = line.match(/\{\s*([^}]+)\s*\}/);
                if (braceMatch) {
                    for (const spec of braceMatch[1].split(",").map(s => s.trim())) {
                        const parts = spec.split(/\s+as\s+/);
                        if (parts.length === 2) {
                            aliases.set(parts[1].trim(), parts[0].trim());
                        }
                    }
                }
            }
            // Drop all import/export-from lines — deps are inlined
            continue;
        }

        // Drop bare re-exports: `export type { X }` / `export { X }`
        // Redundant since inlined deps already export these symbols.
        if (/^export\s+(?:type\s+)?\{[^}]+\}\s*;?\s*$/.test(line)) continue;

        // Drop bare side-effect imports
        if (/^import\s+["']\./.test(line)) continue;

        // Drop `export {};`
        if (line.trim() === "export {};") continue;

        kept.push(line);
    }

    chunks.push(kept.join("\n"));
}

function resolveDecl(dir, specifier) {
    for (const c of [specifier + ".d.ts", specifier + "/index.d.ts"]) {
        const full = path.join(dir, c);
        if (fs.existsSync(full)) return full;
    }
    return null;
}

// --- Main ---
collect(path.join(TEMP_DIR, "spector.d.ts"));

const preamble = [
    "export as namespace SPECTOR;",
    "",
    "// Ambient type from src/types.d.ts (not imported, so injected manually)",
    "type WebGLObject = {};",
].join("\n");

let output = preamble + "\n\n" + chunks.join("\n\n");

// Replace import aliases with original names in TYPE positions only.
// Use negative lookahead (?!\s*:) to avoid replacing property names
// (property names are always followed by `:`).
for (const [alias, original] of aliases) {
    output = output.replace(
        new RegExp("\\b" + alias + "\\b(?!\\s*:)", "g"),
        original,
    );
}

fs.mkdirSync(path.dirname(OUT_FILE), { recursive: true });
fs.writeFileSync(OUT_FILE, output, "utf-8");

const lineCount = output.split("\n").length;
console.log(`Wrote ${lineCount} lines to dist/spector.d.ts`);
